import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.Crpw6aS5.js";const d=JSON.parse('{"title":"保险浮存金 Insurance Float","description":"伯克希尔的秘密引擎：低成本甚至负成本的浮存金","frontmatter":{"title":"保险浮存金 Insurance Float","description":"伯克希尔的秘密引擎：低成本甚至负成本的浮存金"},"headers":[],"relativePath":"02_concepts/insurance-float.md","filePath":"02_concepts/insurance-float.md"}'),r={name:"02_concepts/insurance-float.md"};function i(h,t,n,p,s,c){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="保险浮存金-insurance-float" tabindex="-1">保险浮存金 Insurance Float <a class="header-anchor" href="#保险浮存金-insurance-float" aria-label="Permalink to &quot;保险浮存金 Insurance Float&quot;">​</a></h1><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1967年/核心总结</td><td style="text-align:left;">1967年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1995年/核心总结</td><td style="text-align:left;">1995年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2005年/核心总结</td><td style="text-align:left;">2005年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2006年/核心总结</td><td style="text-align:left;">2006年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2007年/核心总结</td><td style="text-align:left;">2007年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2010年/核心总结</td><td style="text-align:left;">2010年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2011年/核心总结</td><td style="text-align:left;">2011年]]**</td></tr></tbody></table><hr><h2 id="什么是浮存金" tabindex="-1">什么是浮存金 <a class="header-anchor" href="#什么是浮存金" aria-label="Permalink to &quot;什么是浮存金&quot;">​</a></h2><p>浮存金（Float），是保险公司在日常经营中收取保费与支付理赔之间产生的&quot;时间差资金&quot;。</p><p>投保人提前缴纳保费，而保险公司赔付往往发生在未来某个不确定的时刻。在这段时间里，保险公司实际上&quot;借用&quot;了这笔资金进行投资——而这，正是<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦商业模式的核心秘密。</p><blockquote><p>&quot;保险浮存金指的是我们持有的、尚未支付给投保人的资金。这些资金来自保费收入，在理赔发生前一直存在于我们的账户中。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2005年致股东信</cite></p></blockquote><h2 id="浮存金的成本-关键在于-负成本" tabindex="-1">浮存金的成本：关键在于&quot;负成本&quot; <a class="header-anchor" href="#浮存金的成本-关键在于-负成本" aria-label="Permalink to &quot;浮存金的成本：关键在于&quot;负成本&quot;&quot;">​</a></h2><p>普通的保险公司需要用保费收入来覆盖赔付成本和运营费用，通常只能获得微薄的承保利润（有时甚至是亏损）。但<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的保险帝国不同凡响——它的浮存金成本，长期低于零。</p><p>换句话说，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的投保人实际上在&quot;付钱&quot;让<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>管理他们的资金。</p><blockquote><p>&quot;如果浮存金的成本低于我们为其支付的利息，我们就是在盈利。我们的目标就是以负成本——也就是免费甚至有收益的方式——获取这些资金。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2006年致股东信</cite></p></blockquote><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>曾做过一个经典比喻：想象你每天醒来时口袋里自动多了1万美元，但要等到年底才需要花掉它——你会不会觉得这一天很美好？这就是浮存金的魔力。</p><h2 id="浮存金规模-滚雪球的雪道" tabindex="-1">浮存金规模：滚雪球的雪道 <a class="header-anchor" href="#浮存金规模-滚雪球的雪道" aria-label="Permalink to &quot;浮存金规模：滚雪球的雪道&quot;">​</a></h2><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的浮存金规模随着时间不断增长，如今已达数千亿美元之巨。这个数字之所以惊人，不仅在于规模，更在于其极低的获取成本。</p><blockquote><p>&quot;1967年，我们以860万美元收购了National Indemnity公司，由此开始了浮存金的积累。当时，我们完全没有意识到这个决定将为<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>带来怎样的财务优势。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2010年致股东信</cite></p></blockquote><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的保险业务横跨多个领域：</p><ul><li><strong>通用再保险（General Re）</strong>：全球最大的再保险公司之一</li><li><strong><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>再保险集团（<a href="/03_companies/伯克希尔哈撒韦.html">Berkshire</a> Hathaway Reinsurance Group）</strong>：承接各类复杂的再保险业务</li><li><strong><a href="/03_companies/GEICO.html">GEICO</a></strong>：美国第四大汽车保险公司，直接面向消费者</li><li><strong>BH Direct</strong>：大量小型保险公司的集合体</li></ul><blockquote><p>&quot;我们的保险帝国就像一棵不断长大的摇钱树。每新增一笔浮存金，我们就多了一块可以投资的资金。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2005年致股东信</cite></p></blockquote><h2 id="浮存金的双重价值" tabindex="-1">浮存金的双重价值 <a class="header-anchor" href="#浮存金的双重价值" aria-label="Permalink to &quot;浮存金的双重价值&quot;">​</a></h2><p>浮存金对<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的价值体现在两个层面：</p><h3 id="_1-资金成本优势" tabindex="-1">1. 资金成本优势 <a class="header-anchor" href="#_1-资金成本优势" aria-label="Permalink to &quot;1. 资金成本优势&quot;">​</a></h3><p>由于<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的承保纪律极为严格，其浮存金的实际成本长期为负。这意味着<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>拿到的是&quot;免费的午餐&quot;——甚至是有偿的&quot;午餐&quot;。</p><blockquote><p>&quot;浮存金的成本越低，我们的竞争优势就越大。竞争对手为了获取同样的资金需要付出代价，而我们几乎不用付出任何代价。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2008年致股东信</cite></p></blockquote><h3 id="_2-投资杠杆效应" tabindex="-1">2. 投资杠杆效应 <a class="header-anchor" href="#_2-投资杠杆效应" aria-label="Permalink to &quot;2. 投资杠杆效应&quot;">​</a></h3><p>低成本甚至负成本的浮存金，为<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>提供了巨大的投资杠杆。他可以用这些&quot;借来的钱&quot;（实际上是免费的）在资本市场上进行长期价值投资，而无需向任何人支付利息。</p><blockquote><p>&quot;浮存金让我们能够在投资中运用比自身资本大得多的资金量。这不是杠杆——杠杆需要支付利息——这是免费的资本。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2011年致股东信</cite></p></blockquote><h2 id="浮存金不是理所当然的" tabindex="-1">浮存金不是理所当然的 <a class="header-anchor" href="#浮存金不是理所当然的" aria-label="Permalink to &quot;浮存金不是理所当然的&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>多次强调，浮存金的优势并非永恒不变。它需要两个前提条件：</p><ol><li><strong>承保纪律</strong>：只有在承保业务本身盈利（或至少不亏损过多）的情况下，浮存金才是真正&quot;免费&quot;的</li><li><strong>审慎的理赔管理</strong>：避免大规模的灾难性赔付，否则浮存金会被大量消耗</li></ol><blockquote><p>&quot;浮存金是可以被摧毁的。如果我们盲目追求保费规模而忽视风险定价，浮存金就会变成一颗定时炸弹。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2006年致股东信</cite></p></blockquote><p>这也解释了为什么<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在保险业务上始终保持极度保守的承保纪律——不是为了安全，而是为了保护这条&quot;资金来源的生命线&quot;。</p><h2 id="浮存金与伯克希尔的护城河" tabindex="-1">浮存金与<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的护城河 <a class="header-anchor" href="#浮存金与伯克希尔的护城河" aria-label="Permalink to &quot;浮存金与[[伯克希尔]]的护城河&quot;">​</a></h2><p><a href="/04_people/查理·芒格.html">芒格</a>曾评价说，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的浮存金是&quot;商业史上最重要的竞争优势之一&quot;。正是因为有了低成本甚至负成本的浮存金，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>才能：</p><ul><li>在经济衰退期保持投资能力</li><li>无需担忧短期资金压力，专注于长期价值</li><li>以&quot;耐心资本&quot;的姿态等待最佳投资机会</li></ul><blockquote><p>&quot;如果我们没有这些浮存金，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的增长率会大大降低。正是这些资金让我们能够等待别人无法等待的机会。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2007年致股东信</cite></p></blockquote><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="./underwriting-discipline.html">承保纪律</a> — 浮存金的前提：严格的风险定价</li><li><a href="/search.html?q=[伯克希尔">[伯克希尔</a>的保险帝国](./insurance-empire) — 旗下保险公司的全景图</li><li><a href="./../core-principles/compounding.html">复利的力量</a> — 如何利用浮存金实现复利增长</li><li><a href="./../investment-philosophy/patient-capital.html">耐心资本</a> — 浮存金赋予的长期投资视角</li></ul>',39)])])}const q=e(r,[["render",i]]);export{d as __pageData,q as default};
